// C# — DFS on Graph (Adjacency List)
// Recursive, Iterative, Detect Cycle, Find Path, Count Components
using System.Collections.Generic;

public class Graph
{
    private readonly Dictionary<int, List<int>> _adjList = new();

    public void AddEdge(int u, int v)
    {
        if (!_adjList.ContainsKey(u)) _adjList[u] = new List<int>();
        if (!_adjList.ContainsKey(v)) _adjList[v] = new List<int>();
        _adjList[u].Add(v);
        _adjList[v].Add(u); // undirected graph
    }

    // Recursive DFS
    public void DFSRecursive(int start)
    {
        var visited = new HashSet<int>();
        DFSHelper(start, visited);
    }
    private void DFSHelper(int node, HashSet<int> visited)
    {
        visited.Add(node);
        Console.Write(node + " ");
        foreach (var neighbor in _adjList.GetValueOrDefault(node, new List<int>()))
            if (!visited.Contains(neighbor))
                DFSHelper(neighbor, visited);
    }

    // Iterative DFS
    public void DFSIterative(int start)
    {
        var visited = new HashSet<int>();
        var stack = new Stack<int>();
        stack.Push(start);
        while (stack.Count > 0)
        {
            int node = stack.Pop();
            if (visited.Contains(node)) continue;
            visited.Add(node);
            Console.Write(node + " ");
            foreach (var neighbor in _adjList.GetValueOrDefault(node, new List<int>()))
                if (!visited.Contains(neighbor))
                    stack.Push(neighbor);
        }
    }

    // Detect Cycle (undirected graph)
    public bool HasCycle()
    {
        var visited = new HashSet<int>();
        foreach (var node in _adjList.Keys)
            if (!visited.Contains(node))
                if (CycleHelper(node, visited, -1))
                    return true;
        return false;
    }
    private bool CycleHelper(int node, HashSet<int> visited, int parent)
    {
        visited.Add(node);
        foreach (var neighbor in _adjList.GetValueOrDefault(node, new List<int>()))
        {
            if (!visited.Contains(neighbor))
            {
                if (CycleHelper(neighbor, visited, node)) return true;
            }
            else if (neighbor != parent) return true; // visited and not parent = cycle
        }
        return false;
    }

    // Find Path between src and dest
    public List<int>? FindPath(int src, int dest)
    {
        var visited = new HashSet<int>();
        var path = new List<int>();
        return PathHelper(src, dest, visited, path) ? path : null;
    }
    private bool PathHelper(int node, int dest, HashSet<int> visited, List<int> path)
    {
        visited.Add(node);
        path.Add(node);
        if (node == dest) return true;
        foreach (var neighbor in _adjList.GetValueOrDefault(node, new List<int>()))
            if (!visited.Contains(neighbor))
                if (PathHelper(neighbor, dest, visited, path)) return true;
        path.RemoveAt(path.Count - 1); // backtrack
        return false;
    }

    // Count Connected Components
    public int CountComponents()
    {
        var visited = new HashSet<int>();
        int count = 0;
        foreach (var node in _adjList.Keys)
        {
            if (!visited.Contains(node))
            {
                DFSHelper(node, visited);
                count++;
            }
        }
        return count;
    }

    // Search for item X — returns true if X exists in the graph
    public bool SearchFor(int target)
    {
        var visited = new HashSet<int>();
        foreach (var node in _adjList.Keys)
            if (!visited.Contains(node))
                if (SearchHelper(node, target, visited)) return true;
        return false;
    }
    private bool SearchHelper(int node, int target, HashSet<int> visited)
    {
        visited.Add(node);
        if (node == target) return true;
        foreach (var neighbor in _adjList.GetValueOrDefault(node, new List<int>()))
            if (!visited.Contains(neighbor))
                if (SearchHelper(neighbor, target, visited)) return true;
        return false;
    }
}

