class Graph {
    unordered_map<int, vector<int>> adjList;
public:
    void addEdge(int u, int v) {
        adjList[u].push_back(v);
        adjList[v].push_back(u);
    }

    // Recursive DFS
    void dfsRecursive(int start) {
        unordered_set<int> visited;
        dfsHelper(start, visited);
    }
    void dfsHelper(int node, unordered_set<int>& visited) {
        visited.insert(node);
        cout << node << " ";
        for (int neighbor : adjList[node])
            if (!visited.count(neighbor))
                dfsHelper(neighbor, visited);
    }

    // Iterative DFS
    void dfsIterative(int start) {
        unordered_set<int> visited;
        stack<int> stk;
        stk.push(start);
        while (!stk.empty()) {
            int node = stk.top(); stk.pop();
            if (visited.count(node)) continue;
            visited.insert(node);
            cout << node << " ";
            for (int neighbor : adjList[node])
                if (!visited.count(neighbor))
                    stk.push(neighbor);
        }
    }

    // Detect Cycle
    bool hasCycle() {
        unordered_set<int> visited;
        for (auto& [node, _] : adjList)
            if (!visited.count(node))
                if (cycleHelper(node, visited, -1)) return true;
        return false;
    }
    bool cycleHelper(int node, unordered_set<int>& visited, int parent) {
        visited.insert(node);
        for (int neighbor : adjList[node]) {
            if (!visited.count(neighbor)) {
                if (cycleHelper(neighbor, visited, node)) return true;
            } else if (neighbor != parent) return true;
        }
        return false;
    }

    // Find Path
    vector<int> findPath(int src, int dest) {
        unordered_set<int> visited;
        vector<int> path;
        pathHelper(src, dest, visited, path);
        return path;
    }
    bool pathHelper(int node, int dest, unordered_set<int>& visited, vector<int>& path) {
        visited.insert(node);
        path.push_back(node);
        if (node == dest) return true;
        for (int neighbor : adjList[node])
            if (!visited.count(neighbor))
                if (pathHelper(neighbor, dest, visited, path)) return true;
        path.pop_back(); // backtrack
        return false;
    }

    // Count Connected Components
    int countComponents() {
        unordered_set<int> visited;
        int count = 0;
        for (auto& [node, _] : adjList) {
            if (!visited.count(node)) {
                dfsHelper(node, visited);
                count++;
            }
        }
        return count;
    }

    // Search for item X
    bool searchFor(int target) {
        unordered_set<int> visited;
        for (auto& [node, _] : adjList)
            if (!visited.count(node))
                if (searchHelper(node, target, visited)) return true;
        return false;
    }
    bool searchHelper(int node, int target, unordered_set<int>& visited) {
        visited.insert(node);
        if (node == target) return true;
        for (int neighbor : adjList[node])
            if (!visited.count(neighbor))
                if (searchHelper(neighbor, target, visited)) return true;
        return false;
    }
};

