// Java — DFS on Graph (Adjacency List)
// Recursive, Iterative, Detect Cycle, Find Path, Count Components
import java.util.*;

public class Graph {
    private final Map<Integer, List<Integer>> adjList = new HashMap<>();

    public void addEdge(int u, int v) {
        adjList.computeIfAbsent(u, k -> new ArrayList<>()).add(v);
        adjList.computeIfAbsent(v, k -> new ArrayList<>()).add(u);
    }

    // Recursive DFS
    public void dfsRecursive(int start) {
        Set<Integer> visited = new HashSet<>();
        dfsHelper(start, visited);
    }
    private void dfsHelper(int node, Set<Integer> visited) {
        visited.add(node);
        System.out.print(node + " ");
        for (int neighbor : adjList.getOrDefault(node, Collections.emptyList()))
            if (!visited.contains(neighbor))
                dfsHelper(neighbor, visited);
    }

    // Iterative DFS
    public void dfsIterative(int start) {
        Set<Integer> visited = new HashSet<>();
        Deque<Integer> stack = new ArrayDeque<>();
        stack.push(start);
        while (!stack.isEmpty()) {
            int node = stack.pop();
            if (visited.contains(node)) continue;
            visited.add(node);
            System.out.print(node + " ");
            for (int neighbor : adjList.getOrDefault(node, Collections.emptyList()))
                if (!visited.contains(neighbor))
                    stack.push(neighbor);
        }
    }

    // Detect Cycle
    public boolean hasCycle() {
        Set<Integer> visited = new HashSet<>();
        for (int node : adjList.keySet())
            if (!visited.contains(node))
                if (cycleHelper(node, visited, -1)) return true;
        return false;
    }
    private boolean cycleHelper(int node, Set<Integer> visited, int parent) {
        visited.add(node);
        for (int neighbor : adjList.getOrDefault(node, Collections.emptyList())) {
            if (!visited.contains(neighbor)) {
                if (cycleHelper(neighbor, visited, node)) return true;
            } else if (neighbor != parent) return true;
        }
        return false;
    }

    // Find Path
    public List<Integer> findPath(int src, int dest) {
        Set<Integer> visited = new HashSet<>();
        List<Integer> path = new ArrayList<>();
        pathHelper(src, dest, visited, path);
        return path.isEmpty() ? null : path;
    }
    private boolean pathHelper(int node, int dest, Set<Integer> visited, List<Integer> path) {
        visited.add(node);
        path.add(node);
        if (node == dest) return true;
        for (int neighbor : adjList.getOrDefault(node, Collections.emptyList()))
            if (!visited.contains(neighbor))
                if (pathHelper(neighbor, dest, visited, path)) return true;
        path.remove(path.size() - 1); // backtrack
        return false;
    }

    // Count Connected Components
    public int countComponents() {
        Set<Integer> visited = new HashSet<>();
        int count = 0;
        for (int node : adjList.keySet()) {
            if (!visited.contains(node)) {
                dfsHelper(node, visited);
                count++;
            }
        }
        return count;
    }

    // Search for item X
    public boolean searchFor(int target) {
        Set<Integer> visited = new HashSet<>();
        for (int node : adjList.keySet())
            if (!visited.contains(node))
                if (searchHelper(node, target, visited)) return true;
        return false;
    }
    private boolean searchHelper(int node, int target, Set<Integer> visited) {
        visited.add(node);
        if (node == target) return true;
        for (int neighbor : adjList.getOrDefault(node, Collections.emptyList()))
            if (!visited.contains(neighbor))
                if (searchHelper(neighbor, target, visited)) return true;
        return false;
    }

    public static void main(String[] args) {
        Graph graph = new Graph();
        graph.addEdge(0, 1); graph.addEdge(0, 2);
        graph.addEdge(1, 3); graph.addEdge(2, 4);
        graph.dfsRecursive(0);  // 0 1 3 2 4
        graph.dfsIterative(0);  // 0 2 4 1 3
        boolean cycle = graph.hasCycle();             // false
        List<Integer> path = graph.findPath(0, 4);   // [0, 2, 4]
        int components = graph.countComponents();    // 1
    }
}

